import React from 'react';
import { useSelector } from 'react-redux';
import _ from 'lodash';
import { NavLink } from 'react-router-dom';
import style from '../Home/Home.module'


const Shop = (props) => {

    const products = useSelector(state => state.products);

    const handleChange = (event) => {
        event.preventDefault();
        const value = event.target.value;
        props.updateProductFilter(_.filter(products, product => {
            let isContains = product.name.toLowerCase().includes(value.toLowerCase())
            return isContains === true ? product : ''
        }));
    }

    return <React.Fragment>
        <div className="style.home style.home-banner">
            <div className="home-content">
                <div>
                    <span className="style.home-content_title">Welcome to Rabbit Fresh Market</span>
                </div>
                <div>
                    <span className="style.home-content_subtitle">Local Foods at Good Price</span>
                </div>
                <div >
                    <div className="style.home-input_wrapper"  >
                        <input className="style.home-input" onChange={handleChange} type="text" name="name" id='name' placeholder="Search products..." />
                        <NavLink className="style.home-link" to='/search'>
                            <i className="fas fa-search" />
                        </NavLink>
                    </div>
                </div>
            </div>
        </div>
    </React.Fragment>
}

export default Shop;
